import logging
import os

# Set the log storage location
log_path = '/var/log/myapp'

# Create the log directory if it doesn't exist
if not os.path.exists(log_path):
    os.makedirs(log_path)

# Configure log rotation
logging.basicConfig(filename=os.path.join(log_path, 'myapp.log'), filemode='a', maxBytes=1024*1024*5, backupCount=3)

# Set file permissions for log files
os.chmod(os.path.join(log_path, 'myapp.log'), 0o640)

# Create a logger instance
logger = logging.getLogger('myapp')

# Log some messages
logger.info('Starting myapp')
logger.warning('Something went wrong')
logger.error('An error occurred')

# Close the log file
logging.shutdown()